const KIE_API_KEY = ''68b095368a4615c4259c546dee223fe9'';

async function testSeedance\(\) {
  console.log\(''🎬 Testing Seedance 1.5 Pro - Rose Macro Video...\\n''\);

  const requestBody = {
    model: ''seedance-1-5-pro'',
    input: {
      prompt: ''Stunning macro cinematography of a perfect red rose. Extreme close-up of velvety petals with morning dewdrops. Camera slowly moves across the rose surface revealing intricate petal textures. Soft focus transitions between different parts of the flower. Rich crimson colors, dramatic lighting. Water droplets catching light like diamonds. Professional studio macro photography style, 4K ultra-detailed.'',
      aspect_ratio: ''9:16'',
      duration: ''12'',
      resolution: ''720p'',
      generate_audio: false
    }
  };

  console.log\(''Request:'', JSON.stringify\(requestBody, null, 2\)\);
  console.log\(''\\nSending to KIE AI...\\n''\);

  const response = await fetch\(''https://api.kie.ai/api/v1/jobs/createTask'', {
    method: ''POST'',
    headers: {
      ''Content-Type'': ''application/json'',
      ''Authorization'': ''Bearer '' + KIE_API_KEY
    },
    body: JSON.stringify\(requestBody\)
  }\);

  const result = await response.json\(\);
  console.log\(''Response:'', JSON.stringify\(result, null, 2\)\);

  if \(result.code === 200 && result.data?.taskId\) {
    console.log\(''\\n✅ Task created:'', result.data.taskId\);
    console.log\(''\\nPolling for result...''\);

    for \(let i = 0; i < 60; i++\) {
      await new Promise\(r => setTimeout\(r, 5000\)\);

      const poll = await fetch\(''https://api.kie.ai/api/v1/jobs/recordInfo?taskId='' + result.data.taskId, {
        headers: { ''Authorization'': ''Bearer '' + KIE_API_KEY }
      }\);
      const pollResult = await poll.json\(\);
      const state = pollResult.data?.state;

      process.stdout.write\(state === ''generating'' ? ''G'' : state === ''queuing'' ? ''Q'' : state === ''waiting'' ? ''W'' : ''.''\);

      if \(state === ''success''\) {
        console.log\(''\\n\\n✅ Video ready!''\);
        const urls = JSON.parse\(pollResult.data.resultJson\);
        console.log\(''Download URL:'', urls.resultUrls?.[0]\);
        return;
      }
      if \(state === ''fail''\) {
        console.log\(''\\n\\n❌ Failed:'', pollResult.data.failMsg\);
        return;
      }
    }
  }
}

testSeedance\(\);
